   399	// resolveInstallPipeline fetches the published ko_cpi_campaign pipeline row for the app
   400	// and returns its ID. On any failure (DB error, no row, missing ID) it writes an HTTP
   401	// error response and returns ok=false. Callers MUST stop processing when ok is false.
   402	func resolveInstallPipeline(ctx context.Context, w http.ResponseWriter, dao database.AppDAO, appID string) (int, bool) {
   403		posts, err := dao.GetPosts(appID, "", []string{"ko_cpi_campaign"}, []string{"publish"})
   404		if err != nil {
   405			response.HandleError(ctx, w, http.StatusInternalServerError, response.DebugLvl, "Error fetching posts for app", zap.Error(err))
   406			return 0, false
   407		}
   408		if len(posts) == 0 || posts[0].ID < 1 {
   409			response.HandleError(ctx, w, http.StatusBadRequest, response.DebugLvl, "SAN-interlinks not saved, invalid install pipeline for app")
   410			return 0, false
   411		}
   412		return posts[0].ID, true
   413	}
