   415	// syncInstallPostmeta writes the cpi_partner_<networkID> flag plus all template context
   416	// values into app_<appID>.postmeta. Called only after the install pipeline has been
   417	// validated. Returns the first error encountered so the caller can decide whether to
   418	// roll back upstream writes.
   419	func syncInstallPostmeta(dao database.AppDAO, appID string, pipelineID int, contextMeta models.PartnerData, triggerContext map[string]interface{}) error {
   420		if err := dao.UpsertPostmeta(appID, pipelineID, "cpi_partner_"+strconv.Itoa(contextMeta.Network.Id), "true"); err != nil {
   421			return err
   422		}
   423	
   424		for _, value := range contextMeta.Template.ContextMeta {
   425			if value.Input.ID == "" || value.Label.Name == "" || value.Label.Name == "Delivery Delay" || value.Label.Name == "Retry Attempts" {
   426				continue
   427			}
   428			contextValue := fmt.Sprintf("%v", triggerContext[value.Input.ID])
   429			if err := dao.UpsertPostmeta(appID, pipelineID, value.Input.ID, contextValue); err != nil {
   430				return err
   431			}
   432		}
   433		return nil
   434	}
