   436	func (handler EditPostbackHandler) handlePost(w http.ResponseWriter, ctx context.Context, r *http.Request, appID string, accID string, apiKey string, contextMeta models.PartnerData) {
   437		var resp EditPostbackResponse
   438		var editPostbackPostReq models.EditPostbackReq
   439	
   440		if err := json.NewDecoder(r.Body).Decode(&editPostbackPostReq); err != nil {
   441			clog.Error(ctx, "Failed to decode request body", zap.Error(err))
   442			response.HandleError(ctx, w, http.StatusBadRequest, response.DebugLvl, "Invalid request payload")
   443			return
   444		}
   445	
   446		// For install postbacks, validate the app cluster's install pipeline BEFORE writing
   447		// the trigger to GlobalDB. Otherwise a missing/unpublished pipeline leaves an orphan
   448		// trigger that the next retry "fixes," which is the silent-save bug we are guarding
   449		// against.
   450		var installPipelineID int
   451		if editPostbackPostReq.Trigger.Type == "install" {
   452			pipelineID, ok := resolveInstallPipeline(ctx, w, handler.Base.AppDAO, appID)
   453			if !ok {
   454				return
   455			}
   456			installPipelineID = pipelineID
   457		}
   458	
   459		newTriggerID, err := handler.DBGlobal().CreateTrigger(editPostbackPostReq)
   460		if err != nil {
   461			response.HandleError(ctx, w, http.StatusBadRequest, response.DebugLvl, "Error trying to make new trigger for POST req")
   462			return
   463		}
   464	
   465		if editPostbackPostReq.Trigger.Type == "install" {
   466			if err := syncInstallPostmeta(handler.Base.AppDAO, appID, installPipelineID, contextMeta, editPostbackPostReq.Trigger.Context); err != nil {
